INSERT INTO `learning_resource` VALUES (10, '高考俄语听力 题目', '1\nМаша, ты ли это?\n玛莎，是你吗？\n\n2\nОй, Борис, вот это встреча!\n哎，鲍里斯，真是个意外的见面！\n\n3\nСлушай, ты совсем не изменилась, а ведь прошло столько времени.\n听着，你一点都没变，已经过了这么久。\n\n4\nДа, почти десять лет.\n是啊，差不多十年了。\n\n5\nЧто у тебя нового?\n你有什么新鲜事？\n\n6\nНичего особенного.\n没什么特别的。\n\n7\nРаботаю все там же.\n我还是在那儿工作。\n\n8\nЗначит, в лаборатории?\n那就是在实验室？\n\n9\nА семья как?\n家里怎么样？\n\n10\nСколько лет сейчас твоей дочери?\n你女儿现在几岁了？\n\n11\nДевятнадцать.\n十九岁。\n\n12\nСовсем взрослая?\n真是长大了？\n\n13\nУчится?\n她在上学吗？\n\n14\nВ университете.\n在大学。\n\n15\nКак время летит.\n时间过得真快。\n\n16\nДа, подумать только.\n是啊，想想都让人惊讶。\n\n17\nЛена, кто твой папа по профессии?\n莉娜，你爸爸是做什么的？\n\n18\nОн – журналист.\n他是记者。\n\n19\nСаша, что ты обычно делаешь вечером?\n萨沙，你晚上通常做什么？\n\n20\nЯ смотрю телевизор.\n我看电视。\n\n21\nОля, что ты больше любишь – спорт или музыку?\n奥莉亚，你更喜欢运动还是音乐？\n\n22\nМузыку.\n音乐。\n\n23\nДима, куда ты поедешь на летние каникулы?\n迪玛，你暑假打算去哪儿？\n\n24\nВ гости.\n去拜访。\n\n25\nДядя.\n叔叔。\n\n26\nАнна, где ты сейчас учишься?\n安娜，你现在在哪里上学？\n\n27\nВ Московском университете.\n在莫斯科大学。\n\n28\nНа каком факультете?\n哪个系？\n\n29\nНа историческом.\n历史系。\n\n30\nБудьте добры, два билета на Лебединое озеро.\n请给我两张天鹅湖的票。\n\n31\nНа сегодня.\n今天的。\n\n32\nНа сегодня билетов уже нет.\n今天已经没有票了。\n\n33\nЕсть ли у тебя билеты на Лебединое озеро?\n你有天鹅湖的票吗？\n\n34\nЕсть – на завтра.\n有——明天的。\n\n35\nХорошо.\n好的。\n\n36\nДва билета – на завтра.\n两张票——明天的。\n\n37\nС вас – девятьсот рублей.\n你需要支付九百卢布。\n\n38\nБудьте добры, два билета на Лебединое озеро.\n请给我两张天鹅湖的票。\n\n39\nНа сегодня.\n今天的。\n\n40\nНа сегодня билетов уже нет.\n今天已经没有票了。\n\n41\nЕсть – на завтра.\n有——明天的。\n\n42\nХорошо.\n好的。\n\n43\nДва билета на Лебединое озеро.\n两张天鹅湖的票。\n\n44\nНа сегодня.\n今天的。\n\n45\nС вас девятьсот рублей.\n你需要支付九百卢布。\n\n46\nЗдравствуй, Андрей.\n你好，安德烈。\n\n47\nГоворят, ты купил новую квартиру?\n听说你买了新公寓？\n\n48\nДа, мы уже переехали в новый дом.\n是的，我们已经搬进新家了。\n\n49\nПриезжай к нам в среду на новоселье.\n周三来我们家庆祝乔迁吧。\n\n50\nС удовольствием.\n我很乐意。\n\n51\nА квартира большая?\n公寓大吗？\n\n52\nНет, не очень.\n不太大。\n\n53\nДве комнаты.\n两个房间。\n\n54\nА какой этаж?\n几楼？\n\n55\nЧетвёртый.\n第四层。\n\n56\nЗдравствуй, Андрей.\n你好，安德烈。\n\n57\nГоворят, ты купил новую квартиру?\n听说你买了新公寓？\n\n58\nДа, мы уже переехали в новый дом.\n是的，我们已经搬进新家了。\n\n59\nПриезжай к нам в среду на новоселье.\n周三来我们家庆祝乔迁吧。\n\n60\nС удовольствием.\n我很乐意。\n\n61\nА квартира большая?\n公寓大吗？\n\n62\nНет, не очень.\n不太大。\n\n63\nДве комнаты.\n两个房间。\n\n64\nА какой этаж?\n几楼？\n\n65\nЧетвёртый.\n第四层。\n\n66\nНина, хочешь с нами в воскресенье поехать в лес за грибами?\n妮娜，想和我们一起去森林里采蘑菇吗？\n\n67\nС удовольствием, Яша.\n我很乐意，雅沙。\n\n68\nА кто ещё с нами поедет?\n还有谁会和我们一起去？\n\n69\nМои товарищи по работе.\n我的同事们。\n\n70\nНас будет шесть-семь человек.\n我们会有六到七个人。\n\n71\nГде и когда мы собираемся?\n我们在哪里和什么时候集合？\n\n72\nМы собираемся у Казвокзала в восемь тридцать.\n我们在八点半在火车站集合。\n\n73\nХорошо.\n好的。\n\n74\nПостараюсь не опоздать.\n我会尽量不迟到。\n\n75\nНина, хочешь с нами в воскресенье поехать в лес за грибами?\n妮娜，想和我们一起去森林里采蘑菇吗？\n\n76\nС удовольствием, Яша.\n我很乐意，雅沙。\n\n77\nА кто ещё с нами поедет?\n还有谁会和我们一起去？\n\n78\nМои товарищи по работе.\n我的同事们。\n\n79\nНас будет шесть-семь человек.\n我们会有六到七个人。\n\n80\nГде и когда мы собираемся?\n我们在哪里和什么时候集合？\n\n81\nМы собираемся у Казвокзала в восемь тридцать.\n我们在八点半在火车站集合。\n\n82\nХорошо.\n好的。\n\n83\nПостараюсь не опоздать.\n我会尽量不迟到。\n\n84\nСергей, ты любишь спорт?\n谢尔盖，你喜欢运动吗？\n\n85\nДа, Вера, очень люблю.\n是的，维拉，我非常喜欢。\n\n86\nЯ занимаюсь спортом каждый день.\n我每天都在运动。\n\n87\nКакой вид спорта тебе больше всего нравится?\n你最喜欢什么运动？\n\n88\nКонечно, баскетбол.\n当然是篮球。\n\n89\nГде ты играешь в баскетбол?\n你在哪里打篮球？\n\n90\nЯ играю в спортивном зале нашей школы.\n我在我们学校的体育馆打篮球。\n\n91\nА ты чем занимаешься?\n你在做什么？\n\n92\nЯ уже три года плаваю.\n我已经游泳三年了。\n\n93\nДва раза в неделю хожу в бассейн.\n每周去游泳池两次。\n\n94\nТы умеешь плавать?\n你会游泳吗？\n\n95\nДа, я неплохо плаваю.\n是的，我游得不错。\n\n96\nМой отец давно меня научил.\n我父亲很久以前教我的。\n\n97\nСергей, ты любишь спорт?\n谢尔盖，你喜欢运动吗？\n\n98\nДа, Вера, очень люблю.\n是的，维拉，我非常喜欢。\n\n99\nЯ занимаюсь спортом каждый день.\n我每天都在运动。\n\n100\nКакой вид спорта тебе больше всего нравится?\n你最喜欢什么运动？\n\n101\nКонечно, баскетбол.\n当然是篮球。\n\n102\nГде ты играешь в баскетбол?\n你在哪里打篮球？\n\n103\nЯ играю в спортивном зале нашей школы.\n我在我们学校的体育馆打篮球。\n\n104\nА ты чем занимаешься?\n你在做什么？\n\n105\nЯ уже три года плаваю.\n我已经游泳三年了。\n\n106\nДва раза в неделю хожу в бассейн.\n我每周去游泳池两次。\n\n107\nТы умеешь плавать?\n你会游泳吗？\n\n108\nДа, я неплохо плаваю.\n是的，我游得不错。\n\n109\nМой отец давно меня научил.\n我父亲很久以前就教过我。\n\n110\nПосле открытия своей выставки картин русский художник Дмитрий Белюкин неожиданно исчез.\n俄罗斯艺术家德米特里·别柳金在开幕自己的画展后意外消失。\n\n111\nНикто не знал, где он, даже его друзья-художники.\n没有人知道他在哪里，甚至他的艺术家朋友们也不知道。\n\n112\nОн появился только теперь.\n他直到现在才出现。\n\n113\nИ он начал писать через три дня с новой картиной.\n他在三天后开始创作新画。\n\n114\nМне подарили много прекрасных цветов.\n我收到了很多美丽的花。\n\n115\nЯ решил написать картину с этим букетом.\n我决定画一幅这束花的画。\n\n116\nПисать нужно было быстро, ведь цветы живут недолго, — сказал художник.\n画画必须快，因为花的生命不长，——艺术家说。\n\n117\nТак он работает.\n他就是这样工作的。\n\n118\nСтремится всегда написать то, что видит.\n他总是努力画出他所看到的。\n\n119\nЧто ему интересно.\n他感兴趣的东西。\n\n120\nНедавно художник закончил работу над рисунками для книги А.С.\n最近，艺术家完成了为A.S.\n\n121\nПушкина «Евгений Онегин», которая продолжалась целых пятнадцать лет.\n普希金的《叶甫盖尼·奥涅金》绘制插', 'ARTICLE', 'RUSSIAN', '', 0, NULL, 3, NULL, 3, '2026-01-17 19:51:06');
