INSERT INTO `learning_resource` VALUES (12, '【中英双语】mezii BLAST 伦敦英语采访', '【中英双语】mezii BLAST 伦敦英语采访，用于视频理解练习', 'VIDEO', 'ENGLISH', '/uploads/learning/9873c194-0672-446e-bc5d-395137ffa383.mp4', 0, NULL, 5, NULL, 3, '2026-01-17 19:56:05');
INSERT INTO `learning_resource` VALUES (13, '2024年07月N1 答案解析', '問題１ \n１、 正解：1  翻译：防止食品的腐坏。 \n①腐敗（ふはい）：腐坏，腐烂；腐败，堕落。 \n②ふばい：干扰项，无常用词。 \n③ふうはい：干扰项，无常用词。 \n④ふうばい：干扰项，无常用词。 \n２、 正解：3 翻译：这边好像更粗糙一点。 \n①鈍い（にぶい）：钝；迟钝；不清晰。ナイフが鈍くて切れない。小刀不快切不动。 \n②脆い（もろい）：脆弱；易坏；不坚强。岩が風化して脆くなっている。岩石风化变脆了。 \n③粗い（あらい）：粗糙，稀疏；粗枝大叶；荒凉。表面が粗い紙。表面粗糙的纸。 \n④緩い（ゆるい）：松，不严；缓慢；不陡峭。緩いテンポ。慢速。 \n３、 正解：2 翻译：这是保护胃黏膜的药。 \n①せんまく：干扰项，无常用词。 \n②粘膜（ねんまく）：粘膜。鼻の粘膜が弱い。鼻孔粘膜柔弱。 \n③ねんばく：干扰项，无常用词。 \n④せんばく：干扰项，无常用词。 \n４、 正解：2 翻译：根据科学的进步，人们的性命延长了。 \n①じゅうみょう：干扰项，无常用词。 \n②寿命（じゅみょう）：寿命；耐用期限。寿命が尽きる。寿命已到。 \n③受命（じゅめい）：接受命令。 \n④じゅうめい：干扰项，无常用词。 \n５、 正解：４ 翻译：信里是规劝我的内容。 \n①咎める（とがめる）：责难，责备，盘问。彼を咎める理由がない。 \n②責める（せめる）：责备；苛责，折磨；逼问。自分を責めて人を責めるな。要责备自己，不要责\n备他人。 \n③慰める（なぐさめる）：安慰。病気の友を慰める。安慰病患中的友人。 \n④戒める（いましめる）：劝告；规劝；戒除；警惕。子供のいたずらを戒める。规劝孩子不要淘气。 \n６、 正解：３ 翻译：在契约书上签名的时候，有点紧张。 \n①契約書（けいやくしょ）：合同书。契約書を結ぶ。签约。 \n②せつやくしょ：干扰项，无常用词。 \n③誓約書（せいやくしょ）：承诺书。 \n④けつやくしょ：干扰项，无常用词。 \n問題２ \n７、 正解：2 这次发现的遗迹，看来从根本上颠覆了至今以来的学说。 \n①拠点（きょてん）：基地，依据。軍事拠点。军事基地。 \n②根底（こんてい）：根底，基础。根底がしっかりしている。基础稳固。 \n2 \n③原本（げんぽん）：原本，原书。原本に忠実に訳す。对原书忠实翻译。 \n④元祖（がんそ）：始祖，鼻祖。アメリカの元祖はどこから来たか。美国人的祖先是哪里人。 \n８、 正解：4 翻译：因为是1年中最忙的时候，所以连休息日都没休息。 \n①寄付（きふ）：捐献，赠给，赠送。寄付を募る。募捐。 \n②還元（かんげん）：化学还原反应；恢复原状。酸化銅を還元すると銅ができる。 \n氧化铜一还原就成了铜。 \n③進呈（しんてい）：赠送，奉送。無料進呈。免费赠送。 \n④返上（へんじょう）：归还；奉还。休日も返上した。甚至连休息日也不休息。 \n９、 正解：4 翻译：从外部打来的电话需要确认一下来意，然后转接给负责人。 \n①繰り越す（くりこす）：转入；滚入。次のページへ繰り越す。转下页。 \n②差し替える（さしかえる）：更换；替换。カードを差し替える。替换卡片。 \n③引き渡す（ひきわたす）：交给；（犯人）引渡；拉上（幕布）。荷物を引き渡す。交货。 \n④取り次ぐ（とりつぐ）：传达，转达；经销。伝言がおありでしたら、お取り次ぎします。您若有口信，\n我给您转达。 \n１０、 正解：1 翻译：对新生活的期待和不安交织在一起，心情难以平静。 \n①交錯（こうさく）：交錯，錯杂。期待と不安の交錯。期待和不安的交错。 \n②混合（こんごう）：混合不同性质的物体混合在一起。油と水は混合しない。油和水不能混合。 \n③連動（れんどう）：联动，连锁，传动。距離計がカメラのレンズと連動する。测距计跟照相机的\n镜头联动。 \n④反発（はんぱつ）：弹回，回弹；回升；顶撞。彼の発言はみんなの反発を買った。他的讲话遭\n到了大家的反对。 \n１１、 正解：1 翻译：因为有地基薄弱的地方，所以施工难以进展。 \n①難航（なんこう）：困难的航程；难以航行；难以进展。捜査が難航する。搜查难以开展。 \n②低迷（ていめい）：低垂；沉沦，低潮。市場は低迷状態だ。市场处于低迷状态。 \n③衰退（すいたい）：衰退；因衰弱而失去势力。病気で体力が衰退の一途を辿る。因患疾病，体\n力一直衰退下去。 \n④脱落（だつらく）：漏掉，脱离。文字の脱落がないが調べる。审查有无掉字。 \n１２、 正解：3 翻译：会场里面人们的说话声吵吵嚷嚷地很聒噪。 \n①じわじわ：一点一点地，慢慢地。水がじわじわ沁みてくる。水慢慢地渗过来。 \n②どろどろ：沾满泥巴；黏糊；隆隆声。道がどろどろで歩きにくい。路上泥泞不堪不好走。 \n③がやがや：吵吵嚷嚷；喧嚣。部屋の中ががやがやと騒がしい。房间里叽里呱啦很吵闹。 \n④べたべた：厚厚涂膜；纠缠；黏糊糊。絵の具をべたべたと塗る。厚厚地涂一层颜料。 \n１３、 正解：2 翻译：有人邀请我去登山，但是因为我没有什么经验，怕给大家添麻烦所以拒绝\n了…… \n①骨折り：努力，劳苦；尽力；帮忙。骨折りがいがあった。没有白费力气。 \n②足手まとい：缠住手脚，碍手碍脚，绊脚石。子供が足手まといになった。孩子成了累赘。 \n③裏目：尺子的背面刻度；骰子的背面；跟预想不一样的坏的结果。裏目に出る。事与愿违。④\nおよび腰：欠身哈腰；态度暧昧。及び腰で交渉する。以暧昧的态度进行交涉。 \n3 \n問題３ \n１４、 正解：3 翻译：这个决定委托给A公司。 \n委託する（いたくする）：委托。任務を代理人に委託する。把任务委托给代理人。 \n①戻す（もどす）：归还，退回；复原；使……倒退。書類を戻す。把文件退回。 \n②送る（おくる）：送；寄。商品を送る。送货。 \n③任せる（まかせる）：托付；听任，任凭。運を天に任せる。听天由命。 \n④譲る（ゆずる）：转让；让步；出让。道を譲る。让路。 \n１５、 正解：２ 翻译：听了那番话后神清气爽。 \nすがすがしい：神清气爽的，清爽的。すがすがしい気分。清爽的感觉。 \n①憂鬱（ゆううつ）：忧郁不安。憂鬱な顔をする。露出忧郁的神色。 \n②爽やか（さわやか）：清爽，爽朗。爽やかな朝風。清爽的晨风。 \n③楽しい（たのしい）：快乐，愉快。旅行は楽しいです。旅行愉快。 \n④懐かしい（なつかしい）：怀念；眷恋。懐かしい故郷。怀念的故乡。 \n１６、 正解：3 翻译：有必要筹集重建的费用。 \n工面する：设法筹措，筹划，筹款。 \n①減らす（へらす）：减少；饿肚子。運動して脂肪を減らす。锻炼身体减少脂肪。 \n②計算する（けいさんする）：计算。損益を計算する。计算盈亏。 \n③用意する（よういする）准备，预备；警惕，防备。寝具を用意する。准备睡觉用的东西。 \n④支払う（しはらう）：支付。給与を支払う。发工资。 \n１７、 正解：1 翻译：因为是工作的道具，如果被马虎对待的话会让人困扰的。 \nぞんざい：粗糙，草率，马虎。ぞんざいなやりかた。做法粗糙。 \n①雑（ざつ）：粗糙，粗枝大叶。実に雑な字だなあ。真是潦草的字。 \n②変（へん）：奇怪。頭が変だ。脑子不正常。 \n③危険（きけん）：危险。危険に陥る。陷入危机。 \n④強引（ごういん）：强行，强制。そんなに強引にやろうとしたって無理だ。 \n１８、 正解：４ 翻译：男子垂头听着父亲的话。 \nうなだれる：垂头，低头。項垂れて考え込む。低头沉思。 \n①ふざけた態度：不正经的态度。 \n②目を閉じて：闭上眼睛。 \n③まじめな表情：认真的表情。 \n④下を向いて：低垂，向下。 \n１９、 正解：4 翻译：由于天气造成的工程推迟，对于负责人来说是很大的打击。 \n打撃：打击。精神的に強い打撃を受けた。精神上收到强烈打击。 \n①アクシデント：accident。事故。 \n②タブー：taboo。禁忌的言行 \n③プレッシャー： pressure。压力。 \n④ダメージ：dameiji。损坏，破坏，损伤。 \n4 \n問題４ \n２０、 正解：2  \n解析：風潮：潮流，风向，风潮。 \n①流行（りゅうこう）：时髦。 \n②什么事情都按照经济效率来判断是现在社会的风气。 \n③傾向（けいこう）：趋势。 \n④雰囲気（ふんいき）：氛围。 \n２１、 正解：1  \n解析：もたらす：招致，引发，带来（主要跟抽象东西一起搭配）。 \n①科学的快速进步给我们的生活带来的巨大的变化。 \n②持って来た：带来。 \n③鍛える（きたえる）：锻炼。 \n④得る（える）：得到。 \n２２、 正解：3  \n解析：撤回（てっかい）：撤回；撤销。“撤回前言” \n①やめて：放弃 \n②キャンセル：取消 \n③水野氏下午立刻撤回了今天上午在记者会上的发言。 \n④あきらめて：放弃 \n２３、 正解：3  \n解析：補填（ほてん）：填补，补贴，补偿。赤字を補填する。弥补赤字。 \n①記入（きにゅう）：填入。 \n②補充（ほじゅう）：补充。 \n③新业务产生的赤字将由其他业务的收入弥补。 \n④フォロー：跟进。 \n２４、 正解：１  \n解析：コンスタント：一定的；恒长不变的。 \n①这个商品自从发售以来，每个月固定卖50个左右。 \n②ラストシーン：最后一幕。 \n③去掉コンスタント更通顺自然。 \n④老けず（ふけず）：不衰老。 \n２５、 正解：4  \n解析：ずばり：直截了当，开门见山地。 \n①鮮明（せんめい）：鲜明清晰地。 \n②删掉ずばりと \n③きちんと：好好地，整整齐齐地。 \n④被友人直截了当地指出自己的缺点，沮丧了一段时间。 \n問題５ \n5 \n26  \n机の引き出しを整理していたら、以前使っていた電卓が出てきた。まだ使え（ 3 ）するが、使う\n機会がなさそうなので処分しようと思う。 \n在整理桌子抽屉的时候，发现了之前用过的台式电子计算机。 虽然还能用，但是好像也\n没有使用的机会了，所以想处理掉。 \n1. すら 极端举例 就连～都 \n2. さえ 极端举例 就连～都 \n3.は ①围绕某已知话题进行提问、阐述。②对一般客观事态做出判断。③突出，表示对比。。 \n4.も 也。 \n27 \n彼はわずか27歳（ 1  ） 市長となった。 \n他仅仅27岁的时候就成为了市长。 \n1 にして ①表示时间、次数等，“在⋯⋯的时候““在某个时间段”。彼は 40 歳にして父親になっ\nた。②表示并列，“既是⋯⋯又是⋯⋯”彼は医者にして作家でもある。 \n2 にあって 描述某种场合、时间、情况，“处于⋯”在⋯⋯之下”地球温暖化が進む状況にあって、\n低炭素社会への変革が求められている。 \n3 に際して在……之际（包含“以某件事情为契机”的意思）このたびの私の転職に際しましては、\n大変お世話になりました。 \n4 に先立って 在……之前；留学に先立つ書類の準備に、時間もお金もかかってしまった。 \n28 \n（ホームページで） \n当センターの相談窓口に（ 4 ）、事前にご連絡をお願いいたします。 \n当客人您要来相谈窗口的时候，请事先和我们联系。 \n1 伺って以来 （谦）自从拜访以来 \n2 伺う際は（谦）在拜访之际 \n3 お越しになって以来 （敬）自从您到来之后 \n4 お越しになる際は （敬）在您到来之际 \n29 \n6 歳の息子は、将来私と同じ消防士になりたいと言っている。実際に（ 2 ）、そんなことを言っ\nてくれたことがうれしい。 \n6 岁的儿子说他将来想成为和我一样的消防员。虽然他是否真的会成为消防员还不确定，\n但他说这样的话让我感到很高兴 \n1 なるかどうかに限らず 无论是否成为消防员 \n2 なるかどうかはともかく “是否成为消防员暂且不论”，即把是否成为消防员这个条件放在一\n边，不影响现在的感受。这个选项正好表达了“虽然未来是否成为消防员不确定，但现在听到\n儿子这么说很高兴”的意思，符合句子的语境。 \n3 ならざるを得ないとしても 即使不得不成为（消防员）”，通常用在表达某种不可避免的情况。 \n6 \n4ならざるを得ないばかりか 不仅仅是（不得不成为），而且还……”用于表示一种递进的关系。\n这个选项也不符合句子的语境', 'ARTICLE', 'JAPANESE', '', 0, NULL, 6, NULL, 3, '2026-01-17 20:00:02');
INSERT INTO `learning_resource` VALUES (14, '2024年07月N1 听力音频', '2024年07月N1听力音频，用于日语N1听力练习', 'AUDIO', 'JAPANESE', '/uploads/learning/8f847631-99ff-4220-b496-ada89f9a3884.mp3', 0, '2026-01-18 00:16:33', 7, NULL, 3, '2026-01-17 20:05:55');
INSERT INTO `learning_resource` VALUES (15, '2025年6月 四级真题第1套', 'Part II \nSection A\nListening Comprehension\n(25 minutes)\nDirections: In this section, you will hear three news reports. At the end of each news report, you will hear two or\nthree questions. Both the news report and the questions will be spoken only once. After you hear a question, you\nmust choose the best answer from the four choices marked A), B), C) and D). Then mark the corresponding letter\non Answer Sheet 1 with a single line through the centre.\nQuestions 1 and 2 are based on the news report you have just heard.\n1. A) By slapping some butter on it. \nB) By enhancing its nourishment. \n2. A) To introduce their com to tourists. \nB) To attend an honorary ceremony. \nC) By growing it in South Dakota.\nD) By cooking it in vegetable oil.\nC) To share experience with other com growers.\nD) To exhibit their com at the state\'s Com Palace.\nQuestions 3 and 4 are based on the news report you have just heard.\n3. A) Stole mail several times. \nB) Forged postal keys illegally. \n4. A) A sentence for life. \nB) Loss of all their possessions. \nC) Attacked postmen on multiple occasions.\nD) Broke a number of postal collection boxes.\nC) Twenty-three years\' hard labor.\nD) Up to fifteen years in prison.\nQuestions 5 to 7 are based on the news report you have just heard.\n5. A) It escapes regulation and misleads consumers.\nB) It ignores economically feasible recycling options.\nC) It creates waste and severely impacts the environment.\nD) It produces clothes affordable only to a tiny minority.\n6. A) To cut consumers? expenses in buying quality clothes.\nB) To enable the whole fast-fashion industry to be sustainable.\nC) To incentivize manufacturers to be more consumer-friendly.\nD) To urge manufacturers and consumers to reduce waste.\n7. A) Recognizing the impact on consumers. \nC) Abandoning the current business model.\nB) Identifying the source of the problem. \nD) Establishing powerful regulatory bodies.\n1\n・2025年6月四级真题（第一套）・\nSection B\nDirections: In this section, you will hear two long conversations. At the end of each conversation, you will hear\nfour questions. Both the conversation and the questions will be spoken only once. After you hear a question, you\nmust choose the best answer from the four choices marked A), B), C) and D). Then mark the corresponding letter\non Answer Sheet 1 with a single line through the centre.\nQuestions 8 to 11 are based on the conversation you have just heard.\n8. A) The city\'s rush-hour traffic is intolerable.\nB) She cannot avoid rush-hour traffic.\n9. A) Upgrading subway carriages.\nB) Increasing the number of bus routes.\n10. A) He suffers from rush-hour crowding too.\nB) He is fortunate to live very near to work.\n11. A) Recommend to her a good house near his office.\nB) Send her his housing agenfs telephone number.\nC) The local government is inefficient.\nD) The city is too big to move around easily.\nC) Air conditioning the city\'s subway.\nD) Learning from other big cities.\nC) He takes a half-hour bus ride to work.\nD) He is going to move closer to his office.\nC) Tell her exactly what kind of property to look for.\nD) Make sure the agent finds something good for her.\nQuestions 12 to 15 are based on the conversation you have just heard.\n12. A) He was remembered for the scar on his cheek.\nB) He received a heart operation a few days ago.\n13. A) The man\'s deep sympathy fbr Johnny.\nB) The man\'s use of the expression \'fixed\'.\n14. A) It gave him a noticeable smartness.\nB) It made him appear even more manly.\n15. A) Liberal.\nB) Hostile.\nSection C\nC) He used to wear a sad face in school.\nD) He had some plastic surgery done.\nC) The man\'s covering up of what happened.\nD) The man\'s good memory of his childhood.\nC) It seemed to give him a certain uniqueness.\nD) It seemed to make up for his physical defects.\nC) Indifferent.\nD) Critical.\nDirections: In this section, you will hear three passages. At the end of each passage, you will hear three or four\nquestions. Both the passage and the questions will be spoken only once. After you hear a question, you must\nchoose the best answer from the four choices marked A), B), C) and D). Then mark the corresponding letter on\nAnswer Sheet 1 with a single line through the centre.\nQuestions 16 to 18 are based on the passage you have just heard.\n16. A) Through deliberation.\nB) Through evolution.\n17. A) With people imitating sounds around them.\nB) With people interacting with animals close by.\nC) Through invention.\nD) Through collaboration.\nC) With people showing each other things nearby.\nD) With people trying to string sounds together.\n18. A) Making sounds can free one\'s hands for doing other things.\nB) Making sounds proves markedly easier than sign languages.\n•2025年6月四级真题（第一套）・\n2\nC) Making sounds enables one to express their ideas more explicitly.\nD) Making sounds helps one communicate with people they can\'t see.\nQuestions 19 to 21 are based on the passage you have just heard.\n19. A) Well disciplined. \nB) Quite confident. \nC) Somewhat selfish.\nD) Highly intelligent.', 'ARTICLE', 'ENGLISH', '', 0, '2026-01-18 00:51:27', 9, NULL, 3, '2026-01-17 20:14:14');
