INSERT INTO `words` VALUES (57, '先生 (せんせい)', '老师', '田中先生は優しいです。 (田中老师很温柔。)', 'JAPANESE', 0, '2025-12-24 22:05:17', 2, 0);
INSERT INTO `words` VALUES (58, '学校 (がっこう)', '学校', '学校へ行きます。 (去学校。)', 'JAPANESE', 0, '2025-12-24 22:05:17', 2, 0);
