-- ----------------------------
-- Table structure for learning_record
-- ----------------------------
DROP TABLE IF EXISTS `learning_record`;
CREATE TABLE `learning_record`  (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `user_id` bigint NOT NULL COMMENT '用户ID',
  `word_id` bigint NOT NULL COMMENT '单词ID',
  `book_id` bigint NOT NULL DEFAULT 1 COMMENT '所属单词书ID',
  `stage` int NULL DEFAULT 0 COMMENT '当前复习阶段(0-5)',
  `next_review_date` date NOT NULL COMMENT '下一次复习日期',
  `last_review_date` date NULL DEFAULT NULL COMMENT '上一次复习日期',
  `is_mastered` tinyint(1) NULL DEFAULT 0 COMMENT '是否已掌握(1是 0否)',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_user_word_book`(`user_id` ASC, `word_id` ASC, `book_id` ASC) USING BTREE,
  INDEX `idx_next_review`(`user_id` ASC, `next_review_date` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 212 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '用户学习进度表' ROW_FORMAT = Dynamic;

