-- Table structure for mistake_record
-- ----------------------------
DROP TABLE IF EXISTS `mistake_record`;
CREATE TABLE `mistake_record`  (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `user_id` bigint NOT NULL COMMENT '用户ID',
  `word_id` bigint NOT NULL COMMENT '单词ID',
  `book_id` bigint NOT NULL COMMENT '所属单词书ID',
  `mistake_count` int NULL DEFAULT 1 COMMENT '错误次数',
  `last_mistake_time` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '最后一次错误时间',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_user_word`(`user_id` ASC, `word_id` ASC) USING BTREE,
  INDEX `idx_user_book`(`user_id` ASC, `book_id` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 55 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '错题本' ROW_FORMAT = DYNAMIC;

