  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '单词ID',
  `original_text` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '单词原文(英/日)',
